# shapes.spy - Base shapes module with interfaces and enums

# Enum for shape categories
enum ShapeCategory:
    BASIC = 0
    POLYGON = 1
    CIRCLE = 2

# Interface for renderable objects
interface IRenderable:
    def render(self) -> str: ...

# Abstract base class for shapes
@abstract
class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @abstract
    def area(self) -> float: ...

    @abstract
    def perimeter(self) -> float: ...

    @virtual
    def describe(self) -> str:
        return f"Shape: {self.name}"

class Rect(Shape):
    width: float
    height: float

    def __init__(self, name: str, width: float, height: float):
        super().__init__(name)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

