# geometry.spy - Geometric shapes with inheritance and interfaces

from shapes import Shape, IRenderable, ShapeCategory

# Struct for point coordinates
struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_from_origin(self) -> float:
        return (self.x * self.x + self.y * self.y) ** 0.5

# Circle implementing Shape and IRenderable
class Circle(Shape, IRenderable):
    center: Point
    radius: float
    category: ShapeCategory

    def __init__(self, name: str, center: Point, radius: float):
        super().__init__(name)
        self.center = center
        self.radius = radius
        self.category = ShapeCategory.CIRCLE

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def render(self) -> str:
        return f"Circle at ({self.center.x}, {self.center.y}) r={self.radius}"

    @override
    def describe(self) -> str:
        return f"Circle '{self.name}' with radius {self.radius}"

class Triangle(Shape):
    p1: Point
    p2: Point
    p3: Point

    def __init__(self, name: str, p1: Point, p2: Point, p3: Point):
        super().__init__(name)
        self.p1 = p1
        self.p2 = p2
        self.p3 = p3

    @override
    def area(self) -> float:
        # Shoelace formula for triangle area
        result: float = self.p1.x * (self.p2.y - self.p3.y)
        result += self.p2.x * (self.p3.y - self.p1.y)
        result += self.p3.x * (self.p1.y - self.p2.y)
        return abs(result) / 2.0

    @override
    def perimeter(self) -> float:
        d1: float = self._distance(self.p1, self.p2)
        d2: float = self._distance(self.p2, self.p3)
        d3: float = self._distance(self.p3, self.p1)
        return d1 + d2 + d3

    def _distance(self, a: Point, b: Point) -> float:
        dx: float = b.x - a.x
        dy: float = b.y - a.y
        return (dx * dx + dy * dy) ** 0.5
